    () => ({ display: 'flex', gap: '16px' }),
    []
  );

  return (
    <div style={containerStyle}>
      {sortedProducts.map(p => (
        <span key={p.id}>{p.name}: {formatPrice(p.price)}</span>
      ))}
    </div>
  );
}
