export async function GET(req: Request) {
  const team = await db.teams.findById(teamId);
  const members = await db.users.findByTeamId(teamId);

  const summary = [];
  for (const member of members) {
    const tasks = await db.tasks.findByUserId(member.id);
    const reviews = await db.reviews.findByUserId(member.id);
    summary.push({
      name: member.name,
      taskCount: tasks.length,
      reviewCount: reviews.length,
    });
  }

  return Response.json({ team, summary });
}
